import { streamText } from 'ai';

export async function monitoredStream(prompt: string, userInput: string) {
  const stream = await streamText({
    model: 'gpt-4o-mini',
    prompt: `${prompt}\nUser: ${userInput}`
  });

  return new ReadableStream({
    async start(controller) {
      try {
        for await (const chunk of stream.textStream) {
          if (chunk.includes('ignore previous') || chunk.includes('you are now')) {
            controller.error(new Error('Injection detected in stream'));
            return;
          }
          controller.enqueue(chunk);
        }
      } finally {
        controller.close();
      }
    }
  });
}
