function sanitizeInput(input: string): string {
  return input
    .replace(/ignore[\s\w]*previous[\s\w]*instructions/gi, '[REDACTED]')
    .replace(/you are now|you are\s+/gi, '[REDACTED]')
    .replace(/system prompt|override\s+instructions/gi, '[REDACTED]')
    .replace(/<script|javascript:/gi, '');
}

export async function safeStreamText(userInput: string) {
  const cleanInput = sanitizeInput(userInput);
  return streamText({
    model: 'gpt-4o-mini',
    prompt: `User: ${cleanInput}`,
    tools: {
      safeTool: tool({
        parameters: z.object({ safeParam: z.string() }),
        execute: async () => ({ success: true })
      })
    }
  });
}
